def _install_info() -> str:
    """Return 'vX.Y.Z (abc1234)' — dirigent install version + short commit.

    Commit is resolved from the git repo containing the installed package
    (works for editable/`uv sync --dev` installs). Falls back to 'installed'
    for wheel installs or 'commit unknown' on any failure — never raises.
    """
    import subprocess
    from outbid_dirigent import __version__
    try:
        import outbid_dirigent as _pkg
        pkg_dir = Path(_pkg.__file__).parent
        for parent in [pkg_dir, *pkg_dir.parents]:
            if (parent / ".git").exists():
                result = subprocess.run(
                    ["git", "-C", str(parent), "rev-parse", "--short", "HEAD"],
                    capture_output=True, text=True, timeout=5,
                )
                if result.returncode == 0 and result.stdout.strip():
                    return f"v{__version__} ({result.stdout.strip()})"
                return f"v{__version__} (commit unknown)"
        return f"v{__version__} (installed)"
    except Exception:
        return f"v{__version__} (commit unknown)"


